PRAGMA foreign_keys = ON;

CREATE TABLE categories (
  id TEXT PRIMARY KEY,
  exponent INTEGER NOT NULL CHECK (exponent BETWEEN 2 AND 20),
  left_count INTEGER NOT NULL CHECK (left_count BETWEEN 1 AND 12),
  right_count INTEGER NOT NULL CHECK (right_count BETWEEN 1 AND 12),
  format TEXT NOT NULL CHECK (format IN ('equality', 'near_miss', 'target')),
  notation TEXT
);

CREATE TABLE contributors (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL UNIQUE
);

CREATE TABLE resources (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  title TEXT NOT NULL,
  url TEXT NOT NULL UNIQUE
);

CREATE TABLE category_resources (
  category_id TEXT NOT NULL REFERENCES categories(id) ON DELETE CASCADE,
  resource_id INTEGER NOT NULL REFERENCES resources(id) ON DELETE CASCADE,
  PRIMARY KEY (category_id, resource_id)
);

CREATE TABLE submissions (
  id TEXT PRIMARY KEY,
  category_id TEXT NOT NULL REFERENCES categories(id),
  contributor_id INTEGER NOT NULL REFERENCES contributors(id),
  left_terms TEXT NOT NULL CHECK (json_valid(left_terms)),
  right_terms TEXT NOT NULL CHECK (json_valid(right_terms)),
  tool_text TEXT,
  discovered_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(category_id, left_terms, right_terms)
);

CREATE INDEX submissions_by_category_date ON submissions(category_id, discovered_at DESC);

CREATE TABLE submission_resources (
  submission_id TEXT NOT NULL REFERENCES submissions(id) ON DELETE CASCADE,
  resource_id INTEGER NOT NULL REFERENCES resources(id) ON DELETE CASCADE,
  role TEXT NOT NULL CHECK (role IN ('tool', 'source')),
  PRIMARY KEY (submission_id, resource_id, role)
);

CREATE INDEX submission_resources_by_resource ON submission_resources(resource_id);

CREATE TABLE search_claims (
  id TEXT PRIMARY KEY,
  category_id TEXT NOT NULL REFERENCES categories(id),
  contributor_id INTEGER NOT NULL REFERENCES contributors(id),
  lower_radius TEXT NOT NULL,
  upper_radius TEXT NOT NULL,
  search_type TEXT NOT NULL CHECK (search_type IN ('exhaustive', 'partial')),
  tool_text TEXT,
  comment TEXT,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(category_id, contributor_id, lower_radius, upper_radius, search_type)
);

CREATE INDEX search_claims_category_range ON search_claims(
  category_id,
  LENGTH(upper_radius) DESC,
  upper_radius DESC,
  LENGTH(lower_radius) DESC,
  lower_radius DESC
);

CREATE TABLE search_claim_resources (
  search_claim_id TEXT NOT NULL REFERENCES search_claims(id) ON DELETE CASCADE,
  resource_id INTEGER NOT NULL REFERENCES resources(id) ON DELETE CASCADE,
  PRIMARY KEY (search_claim_id, resource_id)
);

CREATE INDEX search_claim_resources_by_resource ON search_claim_resources(resource_id);

CREATE TRIGGER submissions_target_n_bounds
BEFORE INSERT ON submissions
WHEN NEW.category_id = '5-5-n' AND (
  CAST(json_extract(NEW.right_terms, '$[0]') AS INTEGER) < -1000 OR
  CAST(json_extract(NEW.right_terms, '$[0]') AS INTEGER) > 1000
)
BEGIN
  SELECT RAISE(ABORT, 'N must be between -1000 and 1000');
END;










